import{_ as e,o as l,c as n,a2 as s}from"./chunks/framework.Pywvta2k.js";const y=JSON.parse('{"title":"十二消息卦与子午流注","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/09-医易同源/04-十二消息卦与子午流注.md","filePath":"tcm-data/09-医易同源/04-十二消息卦与子午流注.md","lastUpdated":1781084559000}'),a={name:"tcm-data/09-医易同源/04-十二消息卦与子午流注.md"};function d(r,t,g,i,o,x){return l(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="十二消息卦与子午流注" tabindex="-1">十二消息卦与子午流注 <a class="header-anchor" href="#十二消息卦与子午流注" aria-label="Permalink to &quot;十二消息卦与子午流注&quot;">​</a></h1><blockquote><p>十二消息卦 = 一年的阴阳消长 子午流注 = 一天的阴阳消长 医易结合的时间医学</p></blockquote><hr><h2 id="一、十二消息卦——年的阴阳消长" tabindex="-1">一、十二消息卦——年的阴阳消长 <a class="header-anchor" href="#一、十二消息卦——年的阴阳消长" aria-label="Permalink to &quot;一、十二消息卦——年的阴阳消长&quot;">​</a></h2><p>十二消息卦以十二个卦象代表一年十二个月的阴阳进退：</p><h3 id="卦象与月份对应" tabindex="-1">卦象与月份对应 <a class="header-anchor" href="#卦象与月份对应" aria-label="Permalink to &quot;卦象与月份对应&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    乾☰（四月·纯阳）</span></span>
<span class="line"><span>                      ↑ 阳极</span></span>
<span class="line"><span>       姤䷫（五月）         夬䷪（三月）</span></span>
<span class="line"><span>    ↓ 一阴生              一阴消 ↑</span></span>
<span class="line"><span>       遁䷠（六月）         大壮䷡（二月）</span></span>
<span class="line"><span>    ↓ 二阴生              二阴消 ↑</span></span>
<span class="line"><span>       否䷋（七月）         泰䷊（正月·三阳开泰）</span></span>
<span class="line"><span>    ↓ 三阴生              三阴消 ↑</span></span>
<span class="line"><span>       观䷓（八月）         临䷒（十二月）</span></span>
<span class="line"><span>    ↓ 四阴生              四阴消 ↑</span></span>
<span class="line"><span>       剥䷖（九月）         复䷗（十一月·一阳来复）</span></span>
<span class="line"><span>    ↓ 五阴生              五阴消 ↑</span></span>
<span class="line"><span>                    坤䷁（十月·纯阴）</span></span></code></pre></div><h3 id="消息卦的医学意义" tabindex="-1">消息卦的医学意义 <a class="header-anchor" href="#消息卦的医学意义" aria-label="Permalink to &quot;消息卦的医学意义&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">卦</th><th style="text-align:left;">月份</th><th style="text-align:left;">节气</th><th style="text-align:left;">医理</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>复䷗</strong></td><td style="text-align:left;">十一月</td><td style="text-align:left;">冬至</td><td style="text-align:left;"><strong>一阳来复</strong>——养生最重要的时节！冬至宜静养</td></tr><tr><td style="text-align:left;"><strong>临䷒</strong></td><td style="text-align:left;">十二月</td><td style="text-align:left;">小寒·大寒</td><td style="text-align:left;">二阳渐长</td></tr><tr><td style="text-align:left;"><strong>泰䷊</strong></td><td style="text-align:left;"><strong>正月</strong></td><td style="text-align:left;">立春·雨水</td><td style="text-align:left;"><strong>三阳开泰</strong>——肝气升发之时</td></tr><tr><td style="text-align:left;"><strong>大壮䷡</strong></td><td style="text-align:left;">二月</td><td style="text-align:left;">惊蛰·春分</td><td style="text-align:left;">阳气壮盛</td></tr><tr><td style="text-align:left;"><strong>夬䷪</strong></td><td style="text-align:left;">三月</td><td style="text-align:left;">清明·谷雨</td><td style="text-align:left;">五阳决一阴</td></tr><tr><td style="text-align:left;"><strong>乾䷀</strong></td><td style="text-align:left;">四月</td><td style="text-align:left;">立夏·小满</td><td style="text-align:left;"><strong>纯阳之月</strong>——阳极</td></tr><tr><td style="text-align:left;"><strong>姤䷫</strong></td><td style="text-align:left;">五月</td><td style="text-align:left;">芒种·夏至</td><td style="text-align:left;"><strong>一阴始生</strong>——夏至宜静养</td></tr><tr><td style="text-align:left;"><strong>遁䷠</strong></td><td style="text-align:left;">六月</td><td style="text-align:left;">小暑·大暑</td><td style="text-align:left;">二阴浸长</td></tr><tr><td style="text-align:left;"><strong>否䷋</strong></td><td style="text-align:left;">七月</td><td style="text-align:left;">立秋·处暑</td><td style="text-align:left;"><strong>天地不交</strong>——肺气当令</td></tr><tr><td style="text-align:left;"><strong>观䷓</strong></td><td style="text-align:left;">八月</td><td style="text-align:left;">白露·秋分</td><td style="text-align:left;">阴气渐盛</td></tr><tr><td style="text-align:left;"><strong>剥䷖</strong></td><td style="text-align:left;">九月</td><td style="text-align:left;">寒露·霜降</td><td style="text-align:left;">阴剥阳尽</td></tr><tr><td style="text-align:left;"><strong>坤䷁</strong></td><td style="text-align:left;">十月</td><td style="text-align:left;">立冬·小雪</td><td style="text-align:left;"><strong>纯阴之月</strong>——阴极</td></tr></tbody></table><h3 id="普光的十二月养生关键" tabindex="-1">普光的十二月养生关键 <a class="header-anchor" href="#普光的十二月养生关键" aria-label="Permalink to &quot;普光的十二月养生关键&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">月份</th><th style="text-align:left;">养什么</th><th style="text-align:left;">做什么</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>冬至前后（复卦）</strong></td><td style="text-align:left;">⭐ <strong>养一阳</strong></td><td style="text-align:left;">早睡晚起，不可过劳，节制房事</td></tr><tr><td style="text-align:left;"><strong>正月（泰卦）</strong></td><td style="text-align:left;">养肝</td><td style="text-align:left;">助阳升发，适量运动</td></tr><tr><td style="text-align:left;"><strong>夏至前后（姤卦）</strong></td><td style="text-align:left;">养一阴</td><td style="text-align:left;">不可大汗，潜阳养阴</td></tr><tr><td style="text-align:left;"><strong>七月（否卦）</strong></td><td style="text-align:left;">养肺</td><td style="text-align:left;">开始收敛，重视金气</td></tr></tbody></table><hr><h2 id="二、子午流注——一天的阴阳消长" tabindex="-1">二、子午流注——一天的阴阳消长 <a class="header-anchor" href="#二、子午流注——一天的阴阳消长" aria-label="Permalink to &quot;二、子午流注——一天的阴阳消长&quot;">​</a></h2><h3 id="十二时辰气血流注" tabindex="-1">十二时辰气血流注 <a class="header-anchor" href="#十二时辰气血流注" aria-label="Permalink to &quot;十二时辰气血流注&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>         子时（23-1）胆经 → 一阳生</span></span>
<span class="line"><span>                ↑</span></span>
<span class="line"><span>     亥时（21-23）三焦    丑时（1-3）肝经</span></span>
<span class="line"><span>          ↑                    ↑</span></span>
<span class="line"><span>     戌时（19-21）心包      寅时（3-5）肺经</span></span>
<span class="line"><span>          ↑                    ↑</span></span>
<span class="line"><span>     酉时（17-19）肾经      卯时（5-7）大肠经</span></span>
<span class="line"><span>          ↑                    ↑</span></span>
<span class="line"><span>     申时（15-17）膀胱经    辰时（7-9）胃经</span></span>
<span class="line"><span>          ↑                    ↑</span></span>
<span class="line"><span>     未时（13-15）小肠经    巳时（9-11）脾经</span></span>
<span class="line"><span>                ↑</span></span>
<span class="line"><span>          午时（11-13）心经 → 阳极</span></span></code></pre></div><h3 id="逐时养生要点" tabindex="-1">逐时养生要点 <a class="header-anchor" href="#逐时养生要点" aria-label="Permalink to &quot;逐时养生要点&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">时辰</th><th style="text-align:left;">经络</th><th style="text-align:left;">养生</th><th style="text-align:left;">普光/普明建议</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>子时</strong>23-1</td><td style="text-align:left;"><strong>胆经</strong></td><td style="text-align:left;">⭐ <strong>必须入睡</strong>——胆经当令，一阳生</td><td style="text-align:left;">❌ 加班</td></tr><tr><td style="text-align:left;"><strong>丑时</strong>1-3</td><td style="text-align:left;"><strong>肝经</strong></td><td style="text-align:left;">熟睡养肝血</td><td style="text-align:left;">普光熬夜伤肝→目干涩</td></tr><tr><td style="text-align:left;"><strong>寅时</strong>3-5</td><td style="text-align:left;"><strong>肺经</strong></td><td style="text-align:left;">深度睡眠</td><td style="text-align:left;">普明打鼾或此时加重</td></tr><tr><td style="text-align:left;"><strong>卯时</strong>5-7</td><td style="text-align:left;"><strong>大肠经</strong></td><td style="text-align:left;">起床、排便</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>辰时</strong>7-9</td><td style="text-align:left;"><strong>胃经</strong></td><td style="text-align:left;">⭐ <strong>吃早餐</strong>——胃经气血最旺</td><td style="text-align:left;">必须吃，养中气</td></tr><tr><td style="text-align:left;"><strong>巳时</strong>9-11</td><td style="text-align:left;"><strong>脾经</strong></td><td style="text-align:left;">工作效率高</td><td style="text-align:left;">普光晒太阳最佳时段</td></tr><tr><td style="text-align:left;"><strong>午时</strong>11-13</td><td style="text-align:left;"><strong>心经</strong></td><td style="text-align:left;">⭐ <strong>午休15-30分钟</strong></td><td style="text-align:left;">普明午时犯困与此相关</td></tr><tr><td style="text-align:left;"><strong>未时</strong>13-15</td><td style="text-align:left;"><strong>小肠经</strong></td><td style="text-align:left;">消化吸收</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>申时</strong>15-17</td><td style="text-align:left;"><strong>膀胱经</strong></td><td style="text-align:left;">饮水+排泄</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>酉时</strong>17-19</td><td style="text-align:left;"><strong>肾经</strong></td><td style="text-align:left;">⭐ <strong>日落休息</strong></td><td style="text-align:left;">普明此时最疲惫</td></tr><tr><td style="text-align:left;"><strong>戌时</strong>19-21</td><td style="text-align:left;"><strong>心包经</strong></td><td style="text-align:left;">放松、散步</td><td style="text-align:left;">不宜剧烈运动</td></tr><tr><td style="text-align:left;"><strong>亥时</strong>21-23</td><td style="text-align:left;"><strong>三焦经</strong></td><td style="text-align:left;">⭐ <strong>准备入睡</strong></td><td style="text-align:left;">引火归原的最佳时段</td></tr></tbody></table><h3 id="子午流注与普光-前胸出汗-的关系" tabindex="-1">子午流注与普光&quot;前胸出汗&quot;的关系 <a class="header-anchor" href="#子午流注与普光-前胸出汗-的关系" aria-label="Permalink to &quot;子午流注与普光&quot;前胸出汗&quot;的关系&quot;">​</a></h3><p><strong>运动时前胸出汗多、后背少</strong>，从子午流注看：</p><ul><li>前胸为任脉所过，心经所主</li><li>后背为督脉所过，膀胱经所主</li><li>前胸出汗多 = 心火不降，任脉开泄太过</li><li>后背出汗少 = 督脉阳气不足，膀胱经气化不利</li></ul><p><strong>建议</strong>：运动时间改到<strong>上午巳时（9-11点）</strong> 或<strong>下午申时（15-17点）</strong>，避免在阳气最旺的午时运动加重上焦开泄。</p><hr><h2 id="三、子午流注针法-灵龟八法" tabindex="-1">三、子午流注针法（灵龟八法） <a class="header-anchor" href="#三、子午流注针法-灵龟八法" aria-label="Permalink to &quot;三、子午流注针法（灵龟八法）&quot;">​</a></h2><h3 id="八脉交会穴" tabindex="-1">八脉交会穴 <a class="header-anchor" href="#八脉交会穴" aria-label="Permalink to &quot;八脉交会穴&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">八穴</th><th style="text-align:left;">通八脉</th><th style="text-align:left;">配卦</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>公孙</strong>（脾经）</td><td style="text-align:left;">冲脉</td><td style="text-align:left;">乾☰</td></tr><tr><td style="text-align:left;"><strong>内关</strong>（心包）</td><td style="text-align:left;">阴维</td><td style="text-align:left;">兑☱</td></tr><tr><td style="text-align:left;"><strong>后溪</strong>（小肠）</td><td style="text-align:left;">督脉</td><td style="text-align:left;">离☲</td></tr><tr><td style="text-align:left;"><strong>申脉</strong>（膀胱）</td><td style="text-align:left;">阳跷</td><td style="text-align:left;">震☳</td></tr><tr><td style="text-align:left;"><strong>列缺</strong>（肺经）</td><td style="text-align:left;">任脉</td><td style="text-align:left;">坤☷</td></tr><tr><td style="text-align:left;"><strong>照海</strong>（肾经）</td><td style="text-align:left;">阴跷</td><td style="text-align:left;">艮☶</td></tr><tr><td style="text-align:left;"><strong>外关</strong>（三焦）</td><td style="text-align:left;">阳维</td><td style="text-align:left;">坎☵</td></tr><tr><td style="text-align:left;"><strong>临泣</strong>（胆经）</td><td style="text-align:left;">带脉</td><td style="text-align:left;">巽☴</td></tr></tbody></table><h3 id="简易开穴法" tabindex="-1">简易开穴法 <a class="header-anchor" href="#简易开穴法" aria-label="Permalink to &quot;简易开穴法&quot;">​</a></h3><p>根据日干支和时干支推算——一般可参考专业书籍或软件（如&quot;灵龟八法&quot;APP）。</p><p><strong>普光/普明日常保健不必算穴，主要是掌握时辰养生即可。</strong></p><hr><h2 id="四、普光、普明的时辰养生方案" tabindex="-1">四、普光、普明的时辰养生方案 <a class="header-anchor" href="#四、普光、普明的时辰养生方案" aria-label="Permalink to &quot;四、普光、普明的时辰养生方案&quot;">​</a></h2><h3 id="普光-阳虚寒湿型" tabindex="-1">普光（阳虚寒湿型） <a class="header-anchor" href="#普光-阳虚寒湿型" aria-label="Permalink to &quot;普光（阳虚寒湿型）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">做什么</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>5-7点（卯时）</strong></td><td style="text-align:left;">起床、喝温水</td></tr><tr><td style="text-align:left;"><strong>7-9点（辰时）</strong></td><td style="text-align:left;">早餐+姜枣茶、培中气</td></tr><tr><td style="text-align:left;"><strong>9-11点（巳时）</strong></td><td style="text-align:left;"><strong>晒后背20分钟</strong>+轻度运动</td></tr><tr><td style="text-align:left;"><strong>11-13点（午时）</strong></td><td style="text-align:left;">午餐、午休15分钟</td></tr><tr><td style="text-align:left;"><strong>15-17点（申时）</strong></td><td style="text-align:left;">喝足水、排湿</td></tr><tr><td style="text-align:left;"><strong>17-19点（酉时）</strong></td><td style="text-align:left;">晚餐清淡</td></tr><tr><td style="text-align:left;"><strong>19-21点（戌时）</strong></td><td style="text-align:left;">散步、艾灸关元、泡脚</td></tr><tr><td style="text-align:left;"><strong>21-23点（亥时）</strong></td><td style="text-align:left;">准备入睡</td></tr><tr><td style="text-align:left;"><strong>23点前（子时前）</strong></td><td style="text-align:left;"><strong>必须入睡</strong></td></tr></tbody></table><h3 id="普明-中虚血虚-相火浮越型" tabindex="-1">普明（中虚血虚+相火浮越型） <a class="header-anchor" href="#普明-中虚血虚-相火浮越型" aria-label="Permalink to &quot;普明（中虚血虚+相火浮越型）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">时间</th><th style="text-align:left;">做什么</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>5-7点（卯时）</strong></td><td style="text-align:left;">起床、慢起（不猛起）</td></tr><tr><td style="text-align:left;"><strong>7-9点（辰时）</strong></td><td style="text-align:left;">⭐ <strong>营养早餐</strong>（小米粥+鸡蛋）</td></tr><tr><td style="text-align:left;"><strong>9-11点（巳时）</strong></td><td style="text-align:left;">工作效率高时段</td></tr><tr><td style="text-align:left;"><strong>11-13点（午时）</strong></td><td style="text-align:left;"><strong>午休30分钟</strong>（必睡）</td></tr><tr><td style="text-align:left;"><strong>15-17点（申时）</strong></td><td style="text-align:left;">下午茶（桂圆枸杞水）</td></tr><tr><td style="text-align:left;"><strong>17-19点（酉时）</strong></td><td style="text-align:left;"><strong>休息，不勉强做事</strong></td></tr><tr><td style="text-align:left;"><strong>19-21点（戌时）</strong></td><td style="text-align:left;">散步、放松、按三阴交</td></tr><tr><td style="text-align:left;"><strong>21-23点（亥时）</strong></td><td style="text-align:left;">准备入睡</td></tr><tr><td style="text-align:left;"><strong>23点前</strong></td><td style="text-align:left;"><strong>必须入睡</strong></td></tr></tbody></table><hr><p><em>本条目为精简框架版。可扩展至二十四节气养生全方位方案、灵龟八法详解。</em></p>`,36)])])}const p=e(a,[["render",d]]);export{y as __pageData,p as default};
